import{c as t,Q as a,j as n,m as o}from"./chunks/framework.BPKcPtvA.js";const p=JSON.parse('{"title":"Introduction","description":"","frontmatter":{},"headers":[],"relativePath":"introduction/index.md","filePath":"introduction/index.md","lastUpdated":1780664783000}'),i={name:"introduction/index.md"};function r(s,e,h,c,d,l){return a(),n("div",null,[...e[0]||(e[0]=[o('<h1 id="introduction" tabindex="-1">Introduction <a class="header-anchor" href="#introduction" aria-label="Permalink to &quot;Introduction&quot;">​</a></h1><p>Lightning Development Kit (LDK) is a full and completely standalone Lightning implementation with supporting modules enabling greater flexibility.</p><p>You can build a Lightning node without needing to worry about getting all of the Lightning state machine, routing, and on-chain punishment code (and other chain interactions) exactly correct. LDK tends to be suitable for use cases where a degree of customization is desired, e.g. your own chain sync, your own key management and/or your own storage/backup logic.</p><p>Our <a href="https://github.com/lightningdevkit/ldk-sample" target="_blank" rel="noreferrer">sample node</a> showcases how LDK can be customised. It fetches blockchain data and transacts on-chain via Bitcoin Core RPC/REST. The individual components of the sample are composable. For example, the sample writes channel state to the local filesystem, but this component could be replaced with one that writes this data to the cloud or to multiple locations. You can pick the off-the-shelf parts you want and replace the rest.</p><p>To start building a node with LDK <a href="./../building-a-node-with-ldk/introduction">click here.</a></p><h2 id="references" tabindex="-1">References <a class="header-anchor" href="#references" aria-label="Permalink to &quot;References&quot;">​</a></h2><h3 id="rust-documentation" tabindex="-1"><a href="https://docs.rs/lightning" target="_blank" rel="noreferrer">Rust Documentation</a> <a class="header-anchor" href="#rust-documentation" aria-label="Permalink to &quot;[Rust Documentation](https://docs.rs/lightning)&quot;">​</a></h3><p>These provide the most searchable and comprehensive documentation on LDK. If you&#39;re using Java and want more information on any method/struct/etc., searching the Rust docs for the Rust version of that struct/method is your best bet.</p><h3 id="rust-sample-node" tabindex="-1"><a href="https://github.com/lightningdevkit/ldk-sample" target="_blank" rel="noreferrer">Rust Sample Node</a> <a class="header-anchor" href="#rust-sample-node" aria-label="Permalink to &quot;[Rust Sample Node](https://github.com/lightningdevkit/ldk-sample)&quot;">​</a></h3><p>The sample serves as a complete reference for constructing a Lightning node with the LDK. This is a good starting point if you want a self-guided tour!</p><h3 id="architecture" tabindex="-1"><a href="./architecture">Architecture</a> <a class="header-anchor" href="#architecture" aria-label="Permalink to &quot;[Architecture](architecture.md)&quot;">​</a></h3><p>Gives a high-level organization of LDK and how the pieces fit together. Variations of this diagram are used throughout the site. This is the primary source and is still a work in progress.</p>',12)])])}const m=t(i,[["render",r]]);export{p as __pageData,m as default};
